
"use client";
import { useState, useEffect } from "react";
import Image from 'next/image';
import Link from 'next/link';
import {
  Home,
  FileText,
  CalendarCheck,
  FlaskConical,
  History,
  Settings,
  LogOut,
  Users,
  PlusCircle,
  RefreshCw,
  Monitor,
  Eye
} from 'lucide-react';
import { usePathname } from "next/navigation";
import { useAuth } from "@/contexts/AuthContext";
import { addAuditLogAction, getLabsAction, addLabAction } from "@/app/actions/dbActions";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { toast } from "sonner";
import { Lab } from "@/utils/storage";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
  DialogFooter,
  DialogClose
} from "@/components/ui/dialog";

const AdminSidebar = () => {
    const { user, logout } = useAuth();
    const pathname = usePathname();

    const handleLogout = async () => {
        if(user) {
            await addAuditLogAction({ userId: user.id, userName: user.name, action: 'logout' });
        }
        logout();
    };

    const sidebarNavItems = [
        { title: 'Dashboard', icon: Home, href: '/dashboard' },
        { title: 'Manage Users', icon: Users, href: '/admin/users' },
        { title: 'All Requests', icon: FileText, href: '/admin/requests' },
        { title: 'Attendance Reports', icon: CalendarCheck, href: '/admin/reports' },
        { title: 'Lab Management', icon: FlaskConical, href: '/admin/labs' },
        { title: 'Audit Log', icon: History, href: '/admin/audit' },
        { title: 'System Settings', icon: Settings, href: '/admin/settings' },
    ];

    return (
        <aside className="w-64 bg-white p-5 flex flex-col border-r shrink-0">
            <div className="text-center mb-6 mt-2">
                <Link href="/profile">
                    <div className="w-16 h-16 rounded-md bg-primary text-white flex items-center justify-center mx-auto mb-3 cursor-pointer">
                        <span className="text-2xl font-bold">{user?.name?.charAt(0) || 'A'}</span>
                    </div>
                </Link>
                <h3 className="font-semibold text-gray-800">Administrator</h3>
                <p className="text-sm text-muted-foreground">{user?.name}</p>
            </div>
            
            <Button variant="ghost" className="justify-start gap-3 text-base font-medium text-gray-600 hover:text-primary mb-4">
                <RefreshCw className="w-5 h-5" /> Refresh
            </Button>

            <nav className="flex-grow space-y-2">
                {sidebarNavItems.map((item) => {
                    const isActive = pathname === item.href;
                    return (
                        <Link key={item.title} href={item.href} passHref>
                            <Button
                                variant={isActive ? 'default' : 'ghost'}
                                className={`w-full justify-start gap-3 text-base font-medium ${isActive ? 'text-white' : 'text-gray-600 hover:text-primary hover:bg-primary/5'}`}
                                style={isActive ? { backgroundColor: '#E30613' } : {}}
                            >
                                <item.icon className={`w-5 h-5 ${isActive ? 'text-white' : 'text-gray-400 group-hover:text-primary'}`} />
                                {item.title}
                            </Button>
                        </Link>
                    )
                })}
            </nav>
            
            <div className="mt-auto">
                <Button onClick={handleLogout} variant="ghost" className="w-full justify-start gap-3 text-base font-medium text-red-500 hover:text-red-700 hover:bg-red-50">
                    <LogOut className="w-5 h-5" />
                    Logout
                </Button>
            </div>
        </aside>
    );
}

export default function LabManagementPage() {
    const [labs, setLabs] = useState<Lab[]>([]);
    const [newLabName, setNewLabName] = useState('');
    const [newLabCapacity, setNewLabCapacity] = useState('');
    const [activeTab, setActiveTab] = useState('labs');
    const [isAddLabOpen, setAddLabOpen] = useState(false);

    useEffect(() => {
        fetchData();
    }, []);

    const fetchData = async () => {
        setLabs(await getLabsAction());
    };

    const handleAddLab = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!newLabName || !newLabCapacity) {
            toast.error("Please provide lab name and capacity.");
            return;
        }
        await addLabAction({
            id: `LAB-${Date.now()}`,
            name: newLabName,
            capacity: parseInt(newLabCapacity, 10),
        });
        toast.success("Lab and its PCs have been added successfully.");
        setNewLabName('');
        setNewLabCapacity('');
        fetchData();
        setAddLabOpen(false);
    };
    
    return (
        <div className="min-h-screen bg-gray-50 flex flex-col">
            <header className="bg-primary shadow-lg sticky top-0 z-20">
                <div className="mx-auto px-8 h-16 flex items-center">
                    <Image src="/logo.png" alt="AMA Student Portal" width={150} height={38} priority />
                </div>
            </header>
            <div className="flex flex-1">
                <AdminSidebar />
                <main className="flex-1 p-8 overflow-y-auto">
                    <div className="mb-8">
                        <h1 className="text-3xl font-bold text-gray-800">Lab Management</h1>
                        <p className="text-muted-foreground">Manage labs and rooms</p>
                    </div>

                    <div className="flex items-center gap-4 mb-6">
                        <Button 
                            onClick={() => setActiveTab('labs')}
                            variant={activeTab === 'labs' ? 'default' : 'outline'} 
                            style={activeTab === 'labs' ? { backgroundColor: '#E30613' } : {}}
                        >
                            Labs
                        </Button>
                        <Button 
                            onClick={() => setActiveTab('rooms')}
                            variant={activeTab === 'rooms' ? 'default' : 'outline'}
                            style={activeTab === 'rooms' ? { backgroundColor: '#E30613' } : {}}
                        >
                            Rooms
                        </Button>
                        <Dialog open={isAddLabOpen} onOpenChange={setAddLabOpen}>
                            <DialogTrigger asChild>
                                <Button className="ml-auto bg-primary hover:bg-primary/90 text-white">
                                    <PlusCircle className="mr-2 h-4 w-4"/> Add Lab
                                </Button>
                            </DialogTrigger>
                            <DialogContent>
                                <DialogHeader>
                                    <DialogTitle>Add New LAB</DialogTitle>
                                </DialogHeader>
                                <form onSubmit={handleAddLab} className="space-y-4 pt-4">
                                    <div className="space-y-2">
                                        <Label htmlFor="labName">LAB Name</Label>
                                        <Input id="labName" value={newLabName} onChange={e => setNewLabName(e.target.value)} placeholder="e.g., Computer Lab 1"/>
                                    </div>
                                    <div className="space-y-2">
                                        <Label htmlFor="labCapacity">Capacity</Label>
                                        <Input id="labCapacity" type="number" value={newLabCapacity} onChange={e => setNewLabCapacity(e.target.value)} placeholder="e.g., 30"/>
                                    </div>
                                    <DialogFooter>
                                        <DialogClose asChild><Button type="button" variant="secondary">Cancel</Button></DialogClose>
                                        <Button type="submit" className="bg-primary hover:bg-primary/90 text-white">Add LAB</Button>
                                    </DialogFooter>
                                </form>
                            </DialogContent>
                        </Dialog>
                    </div>
                    
                    {activeTab === 'labs' && (
                         <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                            {labs.map(lab => (
                                <Card key={lab.id} className="bg-white">
                                    <CardHeader>
                                        <CardTitle className="flex items-center gap-2 text-gray-800">
                                            <Monitor className="text-primary"/>
                                            {lab.name}
                                        </CardTitle>
                                    </CardHeader>
                                    <CardContent className="space-y-4">
                                        <p className="text-muted-foreground">Capacity: {lab.capacity} PCs</p>
                                        <Button className="w-full bg-blue-600 hover:bg-blue-700 text-white">
                                            <Eye className="mr-2 h-4 w-4"/> View PCs
                                        </Button>
                                    </CardContent>
                                </Card>
                            ))}
                            {labs.length === 0 && <p className="text-muted-foreground col-span-full text-center">No LABs configured yet.</p>}
                        </div>
                    )}
                    {activeTab === 'rooms' && (
                        <div className="text-center text-muted-foreground py-20 border-2 border-dashed rounded-lg">
                            Room management will be implemented here.
                        </div>
                    )}
                </main>
            </div>
        </div>
    );
}
